import React, { useState } from 'react';
import {
  View,
  Text,
  TextInput,
  TouchableOpacity,
  StyleSheet,
  Alert,
  ActivityIndicator,
  KeyboardAvoidingView,
  Platform,
  ScrollView
} from 'react-native';
import { useApp } from '../context/AppContext';
import { loginUser, registerUser } from '../services/api';
import { t } from '../utils/i18n';


const AuthScreen = ({ navigation }) => {
  const { login, language } = useApp();
  const [isLogin, setIsLogin] = useState(true);
  const [phoneNumber, setPhoneNumber] = useState('');
  const [fullName, setFullName] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async () => {
    if (!phoneNumber || !password) {
      Alert.alert('Missing Fields', 'Please enter phone number and password.');
      return;
    }
    if (!isLogin && !fullName) {
      Alert.alert('Missing Fields', 'Please enter your full name.');
      return;
    }

    setLoading(true);
    try {
      if (isLogin) {
        const data = await loginUser(phoneNumber, password);
        await login(data.token, data.user);
      } else {
        await registerUser(phoneNumber, fullName, password);
        const data = await loginUser(phoneNumber, password);
        await login(data.token, data.user);
      }
      navigation.replace('Dashboard');
    } catch (err) {
      const msg = err.response?.data?.message || 'Something went wrong. Please try again.';
      Alert.alert('Error', msg);
    } finally {
      setLoading(false);
    }
  };

  // Demo mode — skip auth for testing without backend
  const handleDemoLogin = async () => {
    await login('demo-token', { id: 'demo-user', full_name: 'Demo Farmer', phone_number: '+263 77 123 4567' });
    navigation.replace('Dashboard');
  };

  return (
    <KeyboardAvoidingView
      style={styles.container}
      behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
    >
      <ScrollView contentContainerStyle={styles.scrollContent} keyboardShouldPersistTaps="handled">
        {/* Logo Section */}
        <View style={styles.logoSection}>
          <View style={styles.logoCircle}>
            <Text style={styles.logoEmoji}>🌿</Text>
          </View>
          <Text style={styles.appName}>Murimi</Text>
          <Text style={styles.tagline}>AI-Powered Crop Management</Text>
        </View>

        {/* Form Card */}
        <View style={styles.formCard}>
          <Text style={styles.formTitle}>{isLogin ? t('welcome_back', language) : t('create_account', language)}</Text>
          <Text style={styles.formSubtitle}>
            {isLogin ? t('sign_in_msg', language) : t('join_msg', language)}
          </Text>

          {!isLogin && (
            <View style={styles.inputGroup}>
              <Text style={styles.inputLabel}>{t('full_name', language)}</Text>
              <TextInput
                style={styles.input}
                placeholder="Enter your full name"
                placeholderTextColor="#9CA3AF"
                value={fullName}
                onChangeText={setFullName}
                autoCapitalize="words"
              />
            </View>
          )}

          <View style={styles.inputGroup}>
            <Text style={styles.inputLabel}>{t('phone_number', language)}</Text>
            <TextInput
              style={styles.input}
              placeholder="+263 77 123 4567"
              placeholderTextColor="#9CA3AF"
              value={phoneNumber}
              onChangeText={setPhoneNumber}
              keyboardType="phone-pad"
              autoCapitalize="none"
            />
          </View>

          <View style={styles.inputGroup}>
            <Text style={styles.inputLabel}>{t('password', language)}</Text>
            <TextInput
              style={styles.input}
              placeholder="Enter your password"
              placeholderTextColor="#9CA3AF"
              value={password}
              onChangeText={setPassword}
              secureTextEntry
            />
          </View>

          <TouchableOpacity
            style={[styles.submitButton, loading && styles.submitButtonDisabled]}
            onPress={handleSubmit}
            disabled={loading}
          >
            {loading ? (
              <ActivityIndicator color="#FFFFFF" />
            ) : (
              <Text style={styles.submitButtonText}>{isLogin ? t('sign_in', language) : t('create_account', language)}</Text>
            )}
          </TouchableOpacity>

          <TouchableOpacity onPress={() => setIsLogin(!isLogin)} style={styles.toggleButton}>
            <Text style={styles.toggleText}>
              {isLogin ? t('dont_have_account', language) : t('already_have_account', language)}
              <Text style={styles.toggleTextBold}>{isLogin ? t('sign_up', language) : t('sign_in', language)}</Text>
            </Text>
          </TouchableOpacity>
        </View>

        {/* Demo Login */}
        <TouchableOpacity onPress={handleDemoLogin} style={styles.demoButton}>
          <Text style={styles.demoButtonText}>🚜 {t('demo_mode', language)}</Text>
        </TouchableOpacity>
      </ScrollView>
    </KeyboardAvoidingView>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#F0FDF4'
  },
  scrollContent: {
    flexGrow: 1,
    justifyContent: 'center',
    padding: 24
  },
  logoSection: {
    alignItems: 'center',
    marginBottom: 32
  },
  logoCircle: {
    width: 80,
    height: 80,
    borderRadius: 40,
    backgroundColor: '#2c5926',
    alignItems: 'center',
    justifyContent: 'center',
    marginBottom: 16,
    shadowColor: '#2c5926',
    shadowOffset: { width: 0, height: 4 },
    shadowOpacity: 0.3,
    shadowRadius: 8,
    elevation: 8
  },
  logoEmoji: {
    fontSize: 36
  },
  appName: {
    fontSize: 36,
    fontWeight: '800',
    color: '#2c5926',
    letterSpacing: 1
  },
  tagline: {
    fontSize: 14,
    color: '#4B5563',
    marginTop: 4,
    letterSpacing: 0.5
  },
  formCard: {
    backgroundColor: '#FFFFFF',
    borderRadius: 20,
    padding: 24,
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 2 },
    shadowOpacity: 0.08,
    shadowRadius: 12,
    elevation: 4
  },
  formTitle: {
    fontSize: 24,
    fontWeight: '700',
    color: '#111827',
    marginBottom: 4
  },
  formSubtitle: {
    fontSize: 14,
    color: '#6B7280',
    marginBottom: 24
  },
  inputGroup: {
    marginBottom: 16
  },
  inputLabel: {
    fontSize: 13,
    fontWeight: '600',
    color: '#374151',
    marginBottom: 6
  },
  input: {
    backgroundColor: '#F9FAFB',
    borderWidth: 1,
    borderColor: '#E5E7EB',
    borderRadius: 12,
    padding: 14,
    fontSize: 16,
    color: '#111827'
  },
  submitButton: {
    backgroundColor: '#2c5926',
    borderRadius: 12,
    padding: 16,
    alignItems: 'center',
    marginTop: 8,
    shadowColor: '#2c5926',
    shadowOffset: { width: 0, height: 4 },
    shadowOpacity: 0.3,
    shadowRadius: 8,
    elevation: 4
  },
  submitButtonDisabled: {
    opacity: 0.7
  },
  submitButtonText: {
    color: '#FFFFFF',
    fontSize: 16,
    fontWeight: '700'
  },
  toggleButton: {
    marginTop: 16,
    alignItems: 'center'
  },
  toggleText: {
    fontSize: 14,
    color: '#6B7280'
  },
  toggleTextBold: {
    color: '#2c5926',
    fontWeight: '700'
  },
  demoButton: {
    marginTop: 24,
    padding: 14,
    alignItems: 'center',
    borderRadius: 12,
    borderWidth: 1,
    borderColor: '#D1D5DB',
    borderStyle: 'dashed'
  },
  demoButtonText: {
    color: '#6B7280',
    fontSize: 14,
    fontWeight: '500'
  }
});

export default AuthScreen;
